VALUES
  ('social-worker-moex-07710', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就認知行為學派而言，下列何種選項不符合其理論主張與實務干預模式？', '["藉由增強作用，消除非理性認知", "短期內協助個人從危機中重回身心平衡", "透過示範，學習新經驗", "運用系統減敏法修正行為"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07711', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就增權理論觀點而言，下列何種選項不符合其理論主張與實務干預模式？', '["主張干涉主義（antithesis of paternalism）的實務模式", "主張去除制度性的權能障礙，以發揮個人權能", "在倫理價值上，承諾案主充分干預計畫的訂定", "運用「倡導辯護」（advocacy）的策略，促使案主具有批判性思考"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07712', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就生態系統理論觀點而言，下列何種選項不符合其理論主張與實務干預模式？', '["此理論同時重視增進案主生活及環境情境", "認為個人問題乃是個人與其所在空間的生態系統不協調所致", "透過揭開個人內在衝突及根源，修正其行動與生活經驗", "主張增進個人運用環境資源的能力，協助重建個人與環境的交流"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07713', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作倫理的觀點中主張：「倫理標準是基於文化、政治環境、當代的規範與道德標準，以及其他 外在環境等因素考量。所以倫理的考量無法斷言何種信仰或何人的信念優於他人」。請問這是屬於何種 倫理觀點？', '["目的論（teleological theories）", "義務論（de-ontological theories）", "直覺論（intuitionist）", "相對論（relativism）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07714', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作人員參與權益倡導，在社會工作專業上以平等、公平、自由與利他為目標，這是遵從何種社會 工作倫理守則？', '["守密", "追求社會正義", "案主自決", "充實知能"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07715', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Reamer（1990）提出一套解決倫理兩難與抉擇的對照比較原則。有一倫理兩難的案例是：「社會工作人 員應尊重案主教育子女的方法，當案主威脅到孩子受教權的基本福祉時，則社會工作人員應介入父母的 管教方法」。這是採行下列何種倫理抉擇的優先性原則？', '["個人基本福祉的權利優先於他人的自我決定權", "個人自我決定的權利優先於自身的基本福祉", "傷害到維持人類生命、健康、尊嚴時優先於傷害到其他如誠實、保密等可加的事物", "防止傷害的義務與提升公共利益的義務優先於個人財產所有權"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07716', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就任務中心學派的理論觀點而言，下列何種選項不符合其理論主張與實務干預模式？', '["人之所以有問題是病理因素所致", "指認「標的問題」（target problem）是此學派的先決條件", "以「有計畫的短期處遇」取代傳統的長期治療模式", "社工所執行的角色是契約訂定者及行動指導夥伴"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07717', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '因應我國人口快速老化導致之照顧服務需求，行政院於96年4月3日核定「我國長期照顧十年計畫」， 以下有關長期照顧的實施之敘述，何者錯誤？', '["主要服務對象分為四類：⑴65歲以上老人⑵55歲以上山地原住民⑶50歲以上身心障礙者⑷工具性日常 生活活動功能（IADL）失能且獨居之老人", "政府依個案失能程度補助服務時數，服務對象之失能程度分為輕、中、重度三級", "政府依失能者家庭經濟狀況提供不同比率補助，低收入戶由政府全額補助，中低收入者補助60%，一 般家庭補助30%", "地方政府長期照顧管理中心扮演失能者需求綜合評估核心角色"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07718', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在婦女社會工作上，下列那些是促進「婦女安全與保護」權益的福利措施？①強化家庭暴力評估  ②訂', '["推動社區保母支持系統", "推動「婦女數位落差」計畫", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07719', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在身心障礙者社會工作實務上，下列何種不屬於「增進身心障礙者權益維護」目標的福利措施？', '["訂定身心障礙者受輔助宣告及監護宣告之參考指標與後續服務措施", "強化身心障礙者區域性醫療復健服務網絡及轉介服務機制", "發展身心障礙人權保障、身體安全、被剝奪學習、被限制自由等評估指標", "中央主管機關會同目的事業主管機關，鼓勵信託業者辦理身心障礙者財產信託"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
